/// <summary>
/// This is the data contract class for report CylinderTrackingInputReport
/// </summary>
[DataContractAttribute,
SysOperationContractProcessing(classStr(ETGCylinderTrackingInputReportUIBuilder))]
internal final class ETGCylinderTrackingInputReportContract implements SysOperationValidatable
{
    FromDate            fromDate;
    ToDate              toDate;
    List                custAccount;
    List                productNum;
    ETGBusinessSegment  etgBusinessSegment;
    ETGConnectionType   etgConnectionType;
    ETGFilledOrEmpty    etgFilledOrEmpty;
    NoYesId             deposit;

}

